import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './CreateCombinedMaterial.css';

const LaborHoursRecord = ({
    fetchAPI,
    apiBaseUrl,
    employees
}) => {
    const [error, setError] = useState(null);
    const [projects, setProjects] = useState([]);
    const [dayRecords, setDayRecords] = useState({});

    const fetchData = useCallback(async () => {
        try {
            const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
    
            setProjects(projectsResponse);
    
            const initialDayRecords = {};
            employees.forEach(employee => {
                initialDayRecords[employee.empid] = { name: employee.name, description: '', start: '', end: ''};
            });
            setDayRecords(initialDayRecords);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl, employees]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (employeeId, field, value) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                [field]: value,
            }
        }));
    };

    const handleAddDayRecord = (employeeId) => {
        // Define the new day record structure, assuming 'project', 'start', and 'end' are the required fields
        const newDayRecord = { project: '', start: '', end: '' };
    
        // Update the day records state with the new day record for the specific employee
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                entries: [...prevRecords[employeeId].entries, newDayRecord]
            }
        }));
    };
    

    const handleRemoveMaterial = (employeeId, index) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                materials: prevRecords[employeeId].materials.filter((_, idx) => idx !== index)
            }
        }));
    };

    if (error) {
        return <div>Error: {error}</div>;
    }

    return (
        <div className="material-input-form-container">
            {Object.values(dayRecords).map((record, index) => (
                <div key={index} className="material-input-form">
                    <h3>Day Record for {record.name || `Employee ${record.employeeId}`}</h3>
                    <span className="close-popup">&times;</span>
                    <div className="form-row">
                
                        <div className="form-group">
                        <label>Project:</label>
              <Select
                name="project"
                value={dayRecords.project ? { value: dayRecords.project, label: projects.find(project => project.prid === dayRecords.project)?.name } : null}
                options={projects
                  .filter(project => project.status.data[0] === 0) // Filter projects where status.data[0] is 1
                  .map((project) => ({
                    value: project.prid,
                    label: project.name,
                  }))}
                onChange={(selectedOption) => handleChange({ target: { name: 'project', value: selectedOption.value } })}
                placeholder="Select a Project"
                required
              />
            
                        </div>
                        <div className="form-group">
    <label htmlFor={`start-${record.employeeId}`}>Start Time</label>
    <input
        id={`start-${record.employeeId}`}
        type="time"
        name="start"
        value={record.start}
        onChange={(e) => handleChange(record.employeeId, 'start', e.target.value)}
        placeholder="HH:MM"
        className="form-control"
    />
</div>
<div className="form-group">
    <label htmlFor={`end-${record.employeeId}`}>End Time</label>
    <input
        id={`end-${record.employeeId}`}
        type="time"
        name="end"
        value={record.end}
        onChange={(e) => handleChange(record.employeeId, 'end', e.target.value)}
        placeholder="HH:MM"
        className="form-control"
    />
</div>

                    </div>
                    
                    <button onClick={() => handleAddDayRecord(record.employeeId)} className="btn btn-primary add-btn">
    Add Project Record
</button>

                    <button className="btn btn-success save-btn">Save Day Record</button>
                </div>
            ))}
        </div>
    );
};

export default LaborHoursRecord;
